#include "controller.h"

static bool controller_sensor_is_stale(uint32_t now_ms, uint32_t last_ms)
{
    return (uint32_t) (now_ms - last_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static void controller_set_outputs(controller_t *controller, bool inlet_open, bool heater_on, controller_state_t state)
{
    controller->inlet_open = inlet_open;
    controller->heater_on = heater_on;
    controller->state = state;
}

static void controller_set_safe_idle(controller_t *controller)
{
    controller_set_outputs(controller, false, false, CONTROLLER_STATE_SAFE_IDLE);
}

static bool controller_temperature_is_rising(const controller_t *controller)
{
    return controller->has_valid_temperature && (controller->last_temperature_c > controller->previous_temperature_c);
}

static void controller_set_low_level_fill(controller_t *controller)
{
    controller_set_outputs(controller, true, false, CONTROLLER_STATE_FILLING);
}

static void controller_set_safe_heating(controller_t *controller)
{
    controller->safe_heater_on = true;
    controller_set_outputs(controller, false, true, CONTROLLER_STATE_HEATING);
}

static void controller_set_safe_holding(controller_t *controller)
{
    controller_set_outputs(controller, false, controller->safe_heater_on, controller->safe_heater_on ? CONTROLLER_STATE_HEATING : CONTROLLER_STATE_HOLDING);
}

static void controller_set_safe_holding_off(controller_t *controller)
{
    controller->safe_heater_on = false;
    controller_set_outputs(controller, false, false, CONTROLLER_STATE_HOLDING);
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->safe_heater_on = false;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;
    uint32_t now_ms;
    bool sensors_ready;
    bool sensor_stale;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;
    now_ms = input.now_ms;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        if (controller->has_valid_temperature) {
            controller->previous_temperature_c = controller->last_temperature_c;
        } else {
            controller->previous_temperature_c = input.temperature_c;
        }
        controller->has_valid_temperature = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller_set_safe_idle(controller);
        output.timed_out = true;
        goto finalize;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller_set_safe_idle(controller);
        goto finalize;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    sensors_ready = controller->has_valid_temperature && controller->has_valid_level;
    sensor_stale = false;
    if (sensors_ready) {
        sensor_stale =
            controller_sensor_is_stale(now_ms, controller->last_temperature_ms) ||
            controller_sensor_is_stale(now_ms, controller->last_level_ms);
    }

    if (!sensors_ready || sensor_stale) {
        controller_set_safe_idle(controller);
        if (sensor_stale) {
            output.timed_out = true;
        }
        goto finalize;
    }

    if (controller->last_level < CONTROLLER_MIN_HEATING_LEVEL) {
        controller_set_low_level_fill(controller);
        goto finalize;
    }

    controller_set_outputs(controller, false, false, CONTROLLER_STATE_HOLDING);

    if (controller->last_temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        controller_set_safe_holding_off(controller);
    } else if (controller->last_temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
        controller_set_safe_heating(controller);
    } else if (controller->last_temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
        controller_set_safe_holding(controller);
    } else {
        if (controller_temperature_is_rising(controller)) {
            controller_set_safe_holding_off(controller);
        } else {
            controller_set_safe_holding(controller);
        }
    }

finalize:
    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_FILL_LEVEL_THRESHOLD 60
#define CONTROLLER_MIN_HEATING_LEVEL 55
#define CONTROLLER_LEVEL_HIGH_THRESHOLD 75
#define CONTROLLER_TEMP_LOW_THRESHOLD 45
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 48
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TEMPERATURE,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TEMPERATURE,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_IDLE = 0,
    CONTROLLER_STATE_FILLING,
    CONTROLLER_STATE_HEATING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    bool has_valid_temperature;
    int previous_temperature_c;
    int last_temperature_c;
    uint32_t last_temperature_ms;
    bool has_valid_level;
    int last_level;
    uint32_t last_level_ms;
    bool safe_heater_on;
} controller_t;

typedef struct {
    bool inlet_open;
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

